#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t N, p, K; scanf("%" PRId64 " %" PRId64 " %" PRId64, &N, &p, &K);
        int64_t full = N / K;
        int64_t rem = N % K;
        int64_t q = p % K;
        int64_t a = p / K;
        int64_t sumPrev = q * full + (q < rem ? q : rem);
        int64_t ans = sumPrev + a + 1;
        printf("%" PRId64 "\n", ans);
    }
    return 0;
}

